sql:
SELECT rating, slope
FROM course_ratings
WHERE rating = (SELECT MAX(rating) FROM course_ratings);

external_knowledge:
Golf courses have unique identifiers (course_id); 
The differential score measures a player's performance relative to the course rating, taking into account the slope rating of the course; 
The course rating and slope are used to level the playing field so golfers of different skill levels can compete fairly.

sql:
SELECT course_id, course_name
FROM courses
WHERE course_id = (SELECT course_id FROM course_ratings ORDER BY rating DESC LIMIT 1);

SELECT ROUND(AVG(rating)) AS avg_rating_above_overall
FROM course_ratings
WHERE rating > (SELECT AVG(rating) FROM course_ratings);

SELECT yardage AS total_yardage
FROM courses
WHERE rating = (SELECT MAX(rating) FROM courses);

SELECT AVG(rating) as average_rating
FROM course_ratings
WHERE course_id = (SELECT course_id FROM courses ORDER BY par DESC LIMIT 1);

SELECT 
  (SELECT AVG(rating) FROM courses) AS average_course_rating,
  (SELECT AVG(handicap) FROM players) AS average_player_handicap;

SELECT 
  (SELECT AVG(rating) FROM course_ratings) AS average_course_rating,
  (SELECT AVG(score) FROM games) AS average_player_score;
